1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 0.1;
3	const LOYALTY_THRESHOLD = 2;
4	const LOYALTY_DISCOUNT = 0.2;
5	const FOLLOWUP_DISCOUNT = 0.15;
6	
7	interface Item {
8	  type: string;
9	  material?: string;
10	  enchantment?: number;
11	  cursed?: boolean;
12	}
13	
14	interface QuoteStep {
15	  op: "quote";
16	  items: Item[];
17	}
18	
19	interface Customer {
20	  yearsWithMHPCO: number;
21	}
22	
23	interface Scenario {
24	  customer: Customer;
25	  steps: QuoteStep[];
26	}
27	
28	interface QuoteResult {
29	  premium: number;
30	}
31	
32	const COMPONENT_BASE_PREMIUM = 25;
33	
34	const BASE_PREMIUMS: Record<string, number> = {
35	  sword: 100,
36	  amulet: 60,
37	  staff: 80,
38	  potion: 40,
39	  rune: COMPONENT_BASE_PREMIUM,
40	  moonstone: COMPONENT_BASE_PREMIUM,
41	};
42	
43	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
44	const BLOCK_SIZE = 3;
45	const BLOCK_PREMIUM = 60;
46	
47	const formsBlock = (type: string, count: number): boolean =>
48	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
49	
50	const typeBasePremium = (type: string, count: number): number => {
51	  if (formsBlock(type, count)) return BLOCK_PREMIUM;
52	  return count * BASE_PREMIUMS[type];
53	};
54	
55	const policyBasePremium = (items: Item[]): number => {
56	  const counts = new Map<string, number>();
57	  for (const item of items) {
58	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
59	  }
60	  return [...counts].reduce(
61	    (base, [type, count]) => base + typeBasePremium(type, count),
62	    0,
63	  );
64	};
65	
66	const CURSE_SURCHARGE = 0.5;
67	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
68	const HIGH_ENCHANTMENT_THRESHOLD = 5;
69	
70	const SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
71	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
72	  {
73	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
74	    rate: HIGH_ENCHANTMENT_SURCHARGE,
75	  },
76	];
77	
78	const itemSurchargeRate = (item: Item): number =>
79	  SURCHARGE_RULES.reduce(
80	    (rate, rule) => (rule.applies(item) ? rate + rule.rate : rate),
81	    0,
82	  );
83	
84	const itemSurcharge = (item: Item): number =>
85	  itemSurchargeRate(item) * BASE_PREMIUMS[item.type];
86	
87	const itemSurcharges = (items: Item[]): number =>
88	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
89	
90	interface PolicyContext {
91	  customer: Customer;
92	  isFollowUp: boolean;
93	}
94	
95	// Policy-wide modifiers each apply a signed rate to the policy base:
96	// positive rates are surcharges, negative rates are discounts.
97	const POLICY_MODIFIER_RULES: {
98	  applies: (context: PolicyContext) => boolean;
99	  rate: number;
100	}[] = [
101	  { applies: () => true, rate: FIRST_INSURANCE_SURCHARGE },
102	  {
103	    applies: ({ customer }) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD,
104	    rate: -LOYALTY_DISCOUNT,
105	  },
106	  { applies: ({ isFollowUp }) => isFollowUp, rate: -FOLLOWUP_DISCOUNT },
107	];
108	
109	const policyModifierRate = (context: PolicyContext): number =>
110	  POLICY_MODIFIER_RULES.reduce(
111	    (rate, rule) => (rule.applies(context) ? rate + rule.rate : rate),
112	    0,
113	  );
114	
115	// Premiums round up (in the MHPCO's favor); toFixed guards against
116	// floating-point error nudging an exact value over an integer boundary.
117	const roundUpPremium = (amount: number): number =>
118	  Math.ceil(Number(amount.toFixed(6)));
119	
120	const quotePremium = (step: QuoteStep, context: PolicyContext): number => {
121	  const { items } = step;
122	  const policyBase = policyBasePremium(items);
123	  const total =
124	    policyBase +
125	    itemSurcharges(items) +
126	    policyBase * policyModifierRate(context) +
127	    PROCESSING_FEE;
128	  return roundUpPremium(total);
129	};
130	
131	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
132	  let quoteCount = 0;
133	  const results = scenario.steps.map((step) => {
134	    const isFollowUp = quoteCount > 0;
135	    quoteCount += 1;
136	    return { premium: quotePremium(step, { customer: scenario.customer, isFollowUp }) };
137	  });
138	  return { results };
139	};
