export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
  // Every step is a quote for now, so the first quote is the first step.
  // When claim steps interleave, derive isFollowUp from prior quotes instead.
  const results = scenario.steps.map((step, index) => {
    const isFollowUp = index > 0;
    const context: PolicyContext = { customer: scenario.customer, isFollowUp };
    return { premium: quotePremium(step, context) };
  });
  return { results };
};
